# Filter data for Sertraline hydrochloride in the MIDLANDS region
sertraline_midlands = df[(df["REGION_NAME"] == "MIDLANDS") &
                         (df["BNF_CHEMICAL_SUBSTANCE"] == "Sertraline hydrochloride")]

