"""### Question 2: Create *annual* summary statistics, for the min, Q1, median, Q3 and maximum national monthly prescribing cost (i.e. all drugs across all regions)

"""

import pandas as pd

# Load the dataset
file_path = "BSA_ODP_PCA_REGIONAL_DRUG_SUMMARY.csv"
df = pd.read_csv(file_path)

# Extract year from YEAR_MONTH
df["YEAR"] = df["YEAR_MONTH"].astype(str).str[:4].astype(int)

# Group by year and month, summing the total national prescribing cost
monthly_national_cost = df.groupby(["YEAR", "YEAR_MONTH"])["COST"].sum().reset_index()

# Compute annual summary statistics
summary_stats = monthly_national_cost.groupby("YEAR")["COST"].describe(percentiles=[0.25, 0.5, 0.75])[["min", "25%", "50%", "75%", "max"]]

# Rename columns for clarity
summary_stats.columns = ["Min", "Q1", "Median", "Q3", "Max"]

# Display results
print(summary_stats)

