"""### Question 5: Create a (pivoted) table that shows the cost of anti-depressant prescribing per region per year?
#### Note: Each row should be a year and each column should be a region.
"""

import pandas as pd

# Load the dataset
file_path = "BSA_ODP_PCA_REGIONAL_DRUG_SUMMARY.csv"
df = pd.read_csv(file_path)

# Extract year from YEAR_MONTH
df["YEAR"] = df["YEAR_MONTH"].astype(str).str[:4].astype(int)

# Filter only anti-depressant drugs (assuming they contain 'antidepressant' or specific drug names)
antidepressants = ["Sertraline hydrochloride", "Fluoxetine", "Citalopram",
                   "Paroxetine", "Venlafaxine", "Mirtazapine", "Duloxetine", "Amitriptyline"]

df_antidepressants = df[df["BNF_CHEMICAL_SUBSTANCE"].isin(antidepressants)]

# Group by year and region, summing the cost
annual_region_cost = df_antidepressants.groupby(["YEAR", "REGION_NAME"])["COST"].sum().reset_index()

# Create pivot table
pivot_table = annual_region_cost.pivot(index="YEAR", columns="REGION_NAME", values="COST")

# Display the pivot table
print(pivot_table)

